<?php

declare(strict_types=1);

namespace App\Tests\Integration\Infrastructure\Anthropic\Client;

use App\Infrastructure\Anthropic\Client\ImageDescriptionGenerator;
use PHPUnit\Framework\Attributes\Test;
use Symfony\Bundle\FrameworkBundle\Test\KernelTestCase;

final class ImageDescriptionGeneratorTest extends KernelTestCase
{
    private ImageDescriptionGenerator $imageDescriptionGenerator;

    protected function setUp(): void
    {
        parent::setUp();

        self::bootKernel();

        $this->imageDescriptionGenerator = static::getContainer()->get(ImageDescriptionGenerator::class);
    }

    #[Test]
    public function canGenerateImageDescription(): void
    {
        $description = $this->imageDescriptionGenerator->describe(
            base64Image: $this->getBase64Image(),
            mimeType: 'image/jpeg',
        );

        self::assertImageDescription($description);
    }

    /**
     * @link https://www.flickr.com/photos/138131221@N04/48807170022/in/photostream/
     */
    private function getBase64Image(): string
    {
        return '';
    }

    private static function assertImageDescription(string $description): void
    {
        $descriptionLength = strlen($description);
        self::assertNotEmpty($description);
        self::assertGreaterThanOrEqual(150, $descriptionLength);
        self::assertLessThanOrEqual(512, $descriptionLength);

        $words = preg_split('/\s+/', trim($description));

        self::assertGreaterThan(30, count($words));
        self::assertStringEndsWith('.', trim($description));
    }
}
